import pymysql
import functions_framework
import os
from typing import Dict, Any, List

# Environment variables for database connection
DB_HOST = os.environ.get('DB_HOST')
DB_USER = os.environ.get('DB_USER')
DB_PASSWORD = os.environ.get('DB_PASSWORD')
DB_NAME = os.environ.get('DB_NAME')

# Allowed fields for filtering
ALLOWED_FIELDS = {
    'id', 'name', 'email', 'status', 'created_at'
}

def validate_and_sanitize_input(params: Dict[str, Any]) -> Dict[str, Any]:
    """Validate and sanitize input parameters"""
    sanitized = {}
    
    # Validate and sanitize filter fields
    for key, value in params.items():
        if key in ALLOWED_FIELDS:
            if isinstance(value, str):
                # Remove potentially dangerous characters
                sanitized[key] = value.replace(';', '').replace('--', '').replace('/*', '').replace('*/', '')
            else:
                sanitized[key] = value
    
    return sanitized

def build_dynamic_query(filters: Dict[str, Any]) -> tuple:
    """Build dynamic SQL query with parameters"""
    base_query = "SELECT * FROM users WHERE 1=1"
    params = []
    
    for field, value in filters.items():
        if value is not None and value != '':
            if isinstance(value, str) and '%' in value:
                base_query += f" AND {field} LIKE %s"
                params.append(value)
            else:
                base_query += f" AND {field} = %s"
                params.append(value)
    
    return base_query, params

@functions_framework.http
def search_users(request):
    """HTTP Cloud Function to search users in Cloud SQL"""
    
    # Handle CORS preflight
    if request.method == 'OPTIONS':
        return ('', 204)
    
    # Validate request method
    if request.method != 'GET':
        return ('Method not allowed', 405)
    
    try:
        # Get request parameters
        params = request.args.to_dict()
        
        # Validate and sanitize input
        sanitized_params = validate_and_sanitize_input(params)
        
        # Build query
        query, query_params = build_dynamic_query(sanitized_params)
        
        # Connect to Cloud SQL
        connection = pymysql.connect(
            host=DB_HOST,
            user=DB_USER,
            password=DB_PASSWORD,
            database=DB_NAME,
            charset='utf8mb4',
            cursorclass=pymysql.cursors.DictCursor,
            autocommit=True
        )
        
        try:
            with connection.cursor() as cursor:
                cursor.execute(query, query_params)
                results = cursor.fetchall()
                
                return ({
                    'status': 'success',
                    'data': results,
                    'count': len(results)
                }, 200)
                
        finally:
            connection.close()
            
    except Exception as e:
        return ({
            'status': 'error',
            'message': 'Internal server error'
        }, 500)